	"github.com/harusame0616/jukubox/lib/env"
)

func TestRequire_ReturnsValue(t *testing.T) {
	t.Setenv("TEST_KEY", "test_value")

	got := env.Require("TEST_KEY")
	if got != "test_value" {
		t.Errorf("got %q, want %q", got, "test_value")
	}
}

func TestRequire_PanicsWhenNotSet(t *testing.T) {
	os.Unsetenv("TEST_KEY_NOT_SET")

	defer func() {
		if r := recover(); r == nil {
			t.Error("expected panic but did not panic")
		}
	}()

	env.Require("TEST_KEY_NOT_SET")
}

